import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";import{o as t,c as i,a as n,b as o,w as l,d as p,e as s,r as c}from"./app.e26ab0af.js";const r={},d=p(`<p>The following guide will explain in detail the structure of a module and how to make a new module <strong>step by step</strong> depending on the difficulty.</p><h2 id="structure-of-a-module" tabindex="-1"><a class="header-anchor" href="#structure-of-a-module" aria-hidden="true">#</a> Structure of a module</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\u{1F4C2} Module folder
|\u2500\u2500 \u{1F4C2} config
|    |\u2500\u2500 \u{1F5D2}\uFE0F migration.php
|    |\u2500\u2500 \u{1F5D2}\uFE0F module.php
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F routes.php
|\u2500\u2500 \u{1F4C2} controllers
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F Module.php
|\u2500\u2500 \u{1F4C2} language
|    \u2514\u2500\u2500 \u{1F4C2} english
|        \u2514\u2500\u2500 \u{1F5D2}\uFE0F module_lang.php
|\u2500\u2500 \u{1F4C2} migrations
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F 20220511000000_create_table.php
|\u2500\u2500 \u{1F4C2} models
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F Module_model.php
\u2514\u2500\u2500 \u{1F4C2} views
     \u2514\u2500\u2500 \u{1F5D2}\uFE0F index.php
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>\u{1F4C2} <strong>config:</strong> Container folder of configs. <ul><li>\u{1F5D2}\uFE0F <strong>migration.php:</strong> Configuration file for migrations.</li><li>\u{1F5D2}\uFE0F <strong>module.php:</strong> Configuration file that provides module information.</li><li>\u{1F5D2}\uFE0F <strong>routes.php:</strong> Configuration file for URI routing.</li></ul></li><li>\u{1F4C2} <strong>controllers:</strong> Container folder of controllers.</li><li>\u{1F4C2} <strong>language:</strong> Container folder of subfolders of language.</li><li>\u{1F4C2} <strong>migrations:</strong> Container folder of database modifier files.</li><li>\u{1F4C2} <strong>models:</strong> Container folder of models.</li><li>\u{1F4C2} <strong>views:</strong> Container folder of view files.</li></ul><div class="custom-container note"><p class="custom-container-title">NOTE</p><p>The structure provided here may vary depending on the developer and the number of elements used.</p></div><h2 id="how-to-create-a-basic-module" tabindex="-1"><a class="header-anchor" href="#how-to-create-a-basic-module" aria-hidden="true">#</a> How to create a basic module?</h2><p>To start this guide we will create a module with the name <code>example</code>, the main focus of this module will be to display a simple message. To do this we will create the following structure:</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\u{1F4C2} example
|\u2500\u2500 \u{1F4C2} config
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F migration.php  &lt;--- New empty file
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F module.php  &lt;--- New empty file
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F routes.php  &lt;--- New empty file
|\u2500\u2500 \u{1F4C2} controllers
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F Example.php  &lt;--- New empty file
|\u2500\u2500 \u{1F4C2} language
|\u2500\u2500 \u{1F4C2} migrations
|\u2500\u2500 \u{1F4C2} models
\u2514\u2500\u2500 \u{1F4C2} views
     \u2514\u2500\u2500 \u{1F5D2}\uFE0F index.php  &lt;--- New empty file
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="custom-container info"><p class="custom-container-title">INFORMATION</p><p>The name <strong>&quot;example&quot;</strong> of the module you can change to whatever you want but keep in mind that you will have to change the name in different parts of the module to match it <strong><em>(remember to capitalize the first letter in the controller name)</em></strong>.</p></div><h3 id="step-1-module-config-file" tabindex="-1"><a class="header-anchor" href="#step-1-module-config-file" aria-hidden="true">#</a> Step 1: Module config file</h3><p>Once we have created the structure mentioned above, we will find and edit the file <code>module.php</code> in which we will write the following:</p><div class="language-php ext-php line-numbers-mode"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
<span class="token function">defined</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;BASEPATH&#39;</span><span class="token punctuation">)</span> <span class="token keyword">OR</span> <span class="token keyword">exit</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;No direct script access allowed&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token keyword">return</span> <span class="token punctuation">[</span>
    <span class="token string single-quoted-string">&#39;name&#39;</span>        <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;Example&#39;</span><span class="token punctuation">,</span>
    <span class="token string single-quoted-string">&#39;description&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;A simple basic module&#39;</span><span class="token punctuation">,</span>
    <span class="token string single-quoted-string">&#39;version&#39;</span>     <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;1.0.0&#39;</span><span class="token punctuation">,</span>
    <span class="token string single-quoted-string">&#39;author&#39;</span>      <span class="token operator">=&gt;</span> <span class="token punctuation">[</span>
        <span class="token string single-quoted-string">&#39;name&#39;</span>    <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;WoW-CMS&#39;</span><span class="token punctuation">,</span>
        <span class="token string single-quoted-string">&#39;website&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;https://wow-cms.com&#39;</span>
    <span class="token punctuation">]</span><span class="token punctuation">,</span>
    <span class="token string single-quoted-string">&#39;dashboard&#39;</span>   <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&#39;</span>
<span class="token punctuation">]</span><span class="token punctuation">;</span>
</span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This file contains important information about the module which is then used in the CMS.</p><table><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><strong>name</strong></td><td>Module name</td></tr><tr><td><strong>description</strong></td><td>Brief description of the module</td></tr><tr><td><strong>version</strong></td><td>Module version</td></tr><tr><td><strong>author name</strong></td><td>Author name</td></tr><tr><td><strong>author website</strong></td><td>Author website</td></tr><tr><td><strong>dashboard</strong></td><td>Route to the admin panel of the module</td></tr></tbody></table><div class="custom-container warning"><p class="custom-container-title">NOTICES</p><p>Remember to change the data provided in the example to your own.</p></div><h3 id="step-2-migration-config-file" tabindex="-1"><a class="header-anchor" href="#step-2-migration-config-file" aria-hidden="true">#</a> Step 2: Migration config file</h3><p>At the end of the previous step, we will find and edit the file <code>migration.php</code> in which we will write the following:</p><div class="language-php ext-php line-numbers-mode"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
<span class="token function">defined</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;BASEPATH&#39;</span><span class="token punctuation">)</span> <span class="token keyword">OR</span> <span class="token keyword">exit</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;No direct script access allowed&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">/*
|--------------------------------------------------------------------------
| Migrations Status
|--------------------------------------------------------------------------
|
| Status of the module&#39;s migration functionality. 
| Disabled by default for security reasons.
|
*/</span>
<span class="token variable">$config</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;migration_enabled&#39;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token constant boolean">false</span><span class="token punctuation">;</span>

<span class="token comment">/*
|--------------------------------------------------------------------------
| Migrations Version
|--------------------------------------------------------------------------
|
| Parameter set as the maximum limit to proceed with the
| migration in the module.
| The version use timestamp format: YYYYMMDDHHIISS
|
*/</span>
<span class="token variable">$config</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;migration_version&#39;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>

<span class="token comment">/*
|--------------------------------------------------------------------------
| Migrations Path
|--------------------------------------------------------------------------
|
| Path to the module migrations folder.
|
*/</span>
<span class="token variable">$config</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;migration_path&#39;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token string single-quoted-string">&#39;../migrations/&#39;</span><span class="token punctuation">;</span>
</span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This configuration file is necessary when the module requires among its functions to create/modify in the database, but for this guide, we will not use it, so we will continue with the steps.</p><h3 id="step-3-routes-config-file" tabindex="-1"><a class="header-anchor" href="#step-3-routes-config-file" aria-hidden="true">#</a> Step 3: Routes config file</h3><p>Now we will find and edit the last config file <code>routes.php</code> in which we will write the following:</p><div class="language-php ext-php line-numbers-mode"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
<span class="token function">defined</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;BASEPATH&#39;</span><span class="token punctuation">)</span> <span class="token keyword">OR</span> <span class="token keyword">exit</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;No direct script access allowed&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token variable">$route</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;example&#39;</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;get&#39;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token string single-quoted-string">&#39;example/index&#39;</span><span class="token punctuation">;</span>
</span></code></pre><div class="highlight-lines"><br><br><br><div class="highlight-line">\xA0</div></div><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This configuration file has as purpose of redirecting the requests to the functions of the controller. so you can limit them to a specific type of request or rename them depending on what you need.</p><h3 id="step-4-controller-file" tabindex="-1"><a class="header-anchor" href="#step-4-controller-file" aria-hidden="true">#</a> Step 4: Controller file</h3><p>Having finished preparing the files in the config folder we will proceed to find and edit the file <code>Example.php</code> in the controller&#39;s folder in which we will write the following:</p><div class="language-php ext-php line-numbers-mode"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
<span class="token function">defined</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;BASEPATH&#39;</span><span class="token punctuation">)</span> <span class="token keyword">OR</span> <span class="token keyword">exit</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;No direct script access allowed&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token keyword">class</span> <span class="token class-name-definition class-name">Example</span> <span class="token keyword">extends</span> <span class="token class-name">MX_Controller</span>
<span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token keyword">function</span> <span class="token function-definition function">__construct</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token keyword static-context">parent</span><span class="token operator">::</span><span class="token function">__construct</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

        <span class="token function">mod_located</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;example&#39;</span><span class="token punctuation">,</span> <span class="token constant boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token keyword">function</span> <span class="token function-definition function">index</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token variable">$data</span> <span class="token operator">=</span> <span class="token punctuation">[</span>
            <span class="token string single-quoted-string">&#39;message&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;Hello world!&#39;</span>
        <span class="token punctuation">]</span><span class="token punctuation">;</span>

        <span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token property">template</span><span class="token operator">-&gt;</span><span class="token function">build</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;index&#39;</span><span class="token punctuation">,</span> <span class="token variable">$data</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</span></code></pre><div class="highlight-lines"><br><br><br><br><br><br><br><br><br><div class="highlight-line">\xA0</div><br><br><div class="highlight-line">\xA0</div><br><div class="highlight-line">\xA0</div><div class="highlight-line">\xA0</div><div class="highlight-line">\xA0</div><br><div class="highlight-line">\xA0</div><br><br></div><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This file is in charge of determining how HTTP requests should be handled. In the example, you can see that several lines have been marked to explain its functionality:</p><ul><li><strong><em>Line 10</em>:</strong> Line located inside the __construct() function is a function to check if the module is installed, if not it will return a 404 page.</li><li><strong><em>Line 13</em>:</strong> The main function of the controller that will process the request.</li><li><strong><em>Lines 15 to 17</em>:</strong> A set of lines that mark an associative array of data where is the message we want to show.</li><li><strong><em>Line 19</em>:</strong> Function of the template library that takes the view file <strong>(index.php)</strong> and passes the data with an associative array <strong>$data</strong>.</li></ul><h3 id="step-5-view-file" tabindex="-1"><a class="header-anchor" href="#step-5-view-file" aria-hidden="true">#</a> Step 5: View file</h3><p>As a final step in this guide of a basic module, we will proceed to find and edit the file <code>index.php</code> in the views folder in which we will write the following:</p><div class="language-php ext-php line-numbers-mode"><pre class="language-php"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>section</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>uk-section uk-section-small primary-bg-section<span class="token punctuation">&quot;</span></span> <span class="token attr-name">uk-height-viewport</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>expand: true<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>uk-container<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h3</span><span class="token punctuation">&gt;</span></span><span class="token php language-php"><span class="token delimiter important">&lt;?=</span> <span class="token variable">$message</span> <span class="token delimiter important">?&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h3</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>section</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="highlight-lines"><br><br><div class="highlight-line">\xA0</div><br><br></div><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This file will display the information to the user. In the example, we use HTML with classes from UIKit 3 and we mark a single line <strong>(Line 3)</strong> which is where our <strong>&#39;Hello World!&#39;</strong> will be shown.</p><p><strong>Now you have your first basic module!</strong> now first enter the admin panel, then in the modules section look for its name and install it. To proceed to see it go to <code>yourdomain.tld/example</code> \u{1F389}</p><h2 id="how-to-create-an-advanced-module" tabindex="-1"><a class="header-anchor" href="#how-to-create-an-advanced-module" aria-hidden="true">#</a> How to create an advanced module?</h2>`,34),u={class:"custom-container warning"},g=n("p",{class:"custom-container-title"},"NOTICES",-1),m=s("Before starting, if you have not yet read the guide on "),v=s("how to create a basic module?"),h=s(", we recommend that you read it to proceed with this advanced guide.");function k(b,f){const e=c("RouterLink");return t(),i("div",null,[d,n("div",u,[g,n("p",null,[m,o(e,{to:"/blizzcms/developer/module.html#how-to-create-a-basic-module"},{default:l(()=>[v]),_:1}),h])])])}var y=a(r,[["render",k],["__file","module.html.vue"]]);export{y as default};
